export function nextGeneration(cells: Cell[]): Cell[] {
  const survivors: Cell[] = [];
  for (const [x, y] of cells) {
    let neighbors = 0;
    for (const [ox, oy] of cells) {
      const dx = ox - x;
      const dy = oy - y;
      if ((dx !== 0 || dy !== 0) && Math.abs(dx) <= 1 && Math.abs(dy) <= 1) {
        neighbors++;
      }
    }
    if (neighbors === 2 || neighbors === 3) {
      survivors.push([x, y]);
    }
  }
  return survivors;
}
```

